\label{main-theorem}
Suppose that Assumptions 1-3 hold. Let $\hat\sigma_F^2=\max\left\{\sigma_F^2,\frac{L\left(f(\mathbf{X}_1)-f^*\right)}{K\gamma^2}\right\}$ with any $\gamma\in(0,1]$, $1-\theta=\sqrt{\frac{L\left(f(\mathbf{X}_1)-f^*\right)}{K\hat\sigma_F^2}}$, $0\leq\beta<1$, $\varepsilon=\sigma_{op}^2$, and $\eta=\sqrt{\frac{\varepsilon\left(f(\mathbf{X}_1)-f^*\right)}{4LK\hat\sigma_F^2}}$. Then for Algorithm \ref{gsoap}, we have
\begin{eqnarray}
\begin{aligned}\label{rate1}
\frac{1}{K}\sum_{k=1}^K\mathbb{E}\left[\left\|\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}\right\|_1\right]\leq 10\sqrt{\frac{\hat\sigma_F^2L\left(f(\mathbf{X}_1)-f^*\right)}{K\sigma_{op}^2}}+4\sqrt{mn}\sqrt[4]{\frac{\hat\sigma_F^2L\left(f(\mathbf{X}_1)-f^*\right)}{K}},
\end{aligned}
\end{eqnarray} 
and
\begin{eqnarray}
\begin{aligned}\label{rate2}
\frac{1}{K}\sum_{k=1}^K\mathbb{E}\left[\left\|\nabla f(\mathbf{X}_k)\right\|_*\right]\leq 10\sqrt{\frac{\hat\sigma_F^2L\left(f(\mathbf{X}_1)-f^*\right)}{K\sigma_{op}^2}}+4\sqrt{mn}\sqrt[4]{\frac{\hat\sigma_F^2L\left(f(\mathbf{X}_1)-f^*\right)}{K}}.
\end{aligned}
\end{eqnarray}

semantic_equivalence_artifact.original_latex_theorem:
As the gradient is $L$-Lipschitz, we have
\begin{eqnarray}
\begin{aligned}\label{equ1}
&f(\X_{k+1})-f(\X_k)\\
\leq&\<\nabla f(\X_k),\X_{k+1}-\X_k\>+\frac{L}{2}\|\X_{k+1}-\X_k\|_F^2\\
=&-\eta\<\nabla f(\X_k),\bP_{k-1}\frac{\M_k'}{\sqrt{\V_k+\varepsilon}}\bQ_{k-1}^T\>+\frac{L\eta^2}{2}\left\|\bP_{k-1}\frac{\M_k'}{\sqrt{\V_k+\varepsilon}}\bQ_{k-1}^T\right\|_F^2\\
=&-\eta\<\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1},\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt{\V_k+\varepsilon}}\>+\frac{L\eta^2}{2}\left\|\bP_{k-1}\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt{\V_k+\varepsilon}}\bQ_{k-1}^T\right\|_F^2\\
\overset{a}=&-\eta\<\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}},\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\>+\frac{L\eta^2}{2}\left\|\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt{\V_k+\varepsilon}}\right\|_F^2\\
\leq&-\eta\<\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}},\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\>+\frac{L\eta^2}{2\sqrt{\varepsilon}}\left\|\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2\\
=&-\frac{\eta}{2}\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2-\frac{\eta}{2}\left\|\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2\\
&+\frac{\eta}{2}\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}-\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2+\frac{L\eta^2}{2\sqrt{\varepsilon}}\left\|\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2\\
\overset{b}\leq&-\frac{\eta}{2}\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2-\frac{\eta}{4}\left\|\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2+\frac{\eta}{2\sqrt{\varepsilon}}\left\|\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}-\bP_{k-1}^T\M_k\bQ_{k-1}\right\|_F^2\\
\overset{c}=&-\frac{\eta}{2}\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2-\frac{\eta}{4}\left\|\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2+\frac{\eta}{2\sqrt{\varepsilon}}\left\|\nabla f(\X_k)-\M_k\right\|_F^2,
\end{aligned}
\end{eqnarray}
where we use the fact that $\|\cdot\|_F$ is a unitarily invariant norm such that $\|\bP\A\bQ^T\|_F=\|\A\|_F$ for orthogonal matrices $\bP$ and $\bQ$ in $\overset{a}=$ and $\overset{c}=$, and let $\eta\leq\frac{\sqrt{\varepsilon}}{2L}$ in $\overset{b}\leq$. Taking expectation on both sides of (\ref{equ1}) with respect to $\zeta_k$ conditioned on $\F_{k-1}$, multiplying both sides of (\ref{GM-dif-equ}) by $\frac{\eta}{2\sqrt{\varepsilon}(1-\theta)}$, and adding to (\ref{equ1}), we have
\begin{eqnarray}
\begin{aligned}\label{equ3}
&\E_k\left[f(\X_{k+1})-f^*+\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\nabla f(\X_k)-\M_k\right\|_F^2+\frac{\eta}{4}\left\|\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2\big| \F_{k-1}\right]\\
\leq&f(\X_k)-f^*-\frac{\eta}{2}\E_k\left[\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2\big| \F_{k-1}\right]\\
& +\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\M_{k-1}-\nabla f(\X_{k-1})\right\|_F^2+ \frac{L^2\eta^3}{2\varepsilon(1-\theta)^2}\left\|\frac{\bP_{k-2}^T\M_{k-1}\bQ_{k-2}}{\sqrt[4]{\V_{k-1}+\varepsilon}}\right\|_F^2 + \frac{\eta(1-\theta)\sigma_F^2}{2\sqrt{\varepsilon}}\\
\leq&f(\X_k)-f^*-\frac{\eta}{2}\E_k\left[\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2\big| \F_{k-1}\right]\\
& +\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\M_{k-1}-\nabla f(\X_{k-1})\right\|_F^2+ \frac{\eta}{4}\left\|\frac{\bP_{k-2}^T\M_{k-1}\bQ_{k-2}}{\sqrt[4]{\V_{k-1}+\varepsilon}}\right\|_F^2 + \frac{\eta(1-\theta)\sigma_F^2}{2\sqrt{\varepsilon}},
\end{aligned}
\end{eqnarray}
where we let $\eta^2\leq\frac{\varepsilon(1-\theta)^2}{2L^2} $ in the last inequality. Define 
\begin{eqnarray}
\begin{aligned}\label{wide-v-def}
\widetilde \V_k=\beta\V_{k-1}+(1-\beta)\left(\left(\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}\right)^2+\sigma_{op}^2\right).
\end{aligned}
\end{eqnarray}
Since $\bP_{k-1}$ and $\bQ_{k-1}$ are not random variables given $\F_{k-1}$, we have
\begin{eqnarray}
\begin{aligned}\label{equ2}
&\E_k\left[\left|\bP_{k-1,:,i}^T\G_k\bQ_{k-1,:,j}\right|^2\big| \F_{k-1}\right]\\
\overset{d}=&\E_k\left[\left|\bP_{k-1,:,i}^T\nabla f(\X_k)\bQ_{k-1,:,j}\right|^2+\left|\bP_{k-1,:,i}^T\left(\nabla f(\X_k)-\G_k\right)\bQ_{k-1,:,j}\right|^2\Big|\F_{k-1}\right]\\
\overset{e}\leq&\E_k\left[\left|\bP_{k-1,:,i}^T\nabla f(\X_k)\bQ_{k-1,:,j}\right|^2+\left\|\nabla f(\X_k)-\G_k\right\|_{op}^2\Big|\F_{k-1}\right]\\
=&\left|\bP_{k-1,:,i}^T\nabla f(\X_k)\bQ_{k-1,:,j}\right|^2+\E_k\left[\left\|\nabla f(\X_k)-\G_k\right\|_{op}^2\Big|\F_{k-1}\right]\\
\overset{f}\leq&\left|\bP_{k-1,:,i}^T\nabla f(\X_k)\bQ_{k-1,:,j}\right|^2+\sigma_{op}^2, 
\end{aligned}
\end{eqnarray}
where we use Assumption 2 in $\overset{d}=$, $\<\x,\y\>\leq\|\x\|\|\y\|$, $\|\A\x\|\leq\|\A\|_{op}\|\x\|$, $\|\bP_{k-1,:,i}\|=1$, and $\|\bQ_{k-1,:,j}\|=1$ in $\overset{e}\leq$, and Assumption 3 in $\overset{f}\leq$. From the concavity of $\sqrt{x}$ and $-\frac{1}{\sqrt{x}}$, we have
\begin{eqnarray}
\begin{aligned}\notag
\E_k\left[\sqrt{\V_{k,i,j}+\varepsilon}\big| \F_{k-1}\right]\leq& \sqrt{\E_k\left[\V_{k,i,j}\big| \F_{k-1}\right]+\varepsilon}\\
=&\sqrt{\beta\V_{k-1,i,j}+(1-\beta)\E_k\left[\left|\bP_{k-1,:,i}^T\G_k\bQ_{k-1,:,j}\right|^2\big| \F_{k-1}\right]+\varepsilon}\\
\leq&\sqrt{\beta\V_{k-1,i,j}+(1-\beta)\left(\left|\bP_{k-1,:,i}^T\nabla f(\X_k)\bQ_{k-1,:,j}\right|^2+\sigma_{op}^2\right)+\varepsilon}\\
=&\sqrt{\widetilde \V_{k,i,j}+\varepsilon}
\end{aligned}
\end{eqnarray}
and
\begin{eqnarray}
\begin{aligned}\notag
\E_k\left[-\frac{\left|\bP_{k-1,:,i}^T\nabla f(\X_k)\bQ_{k-1,:,j}\right|^2}{\sqrt{\V_{k,i,j}+\varepsilon}}\big| \F_{k-1}\right]\leq -\frac{\left|\bP_{k-1,:,i}^T\nabla f(\X_k)\bQ_{k-1,:,j}\right|^2}{\sqrt{\E_k\left[\V_{k,i,j}\big| \F_{k-1}\right]+\varepsilon}}= -\frac{\left|\bP_{k-1,:,i}^T\nabla f(\X_k)\bQ_{k-1,:,j}\right|^2}{\sqrt{\widetilde \V_{k,i,j}+\varepsilon}}.
\end{aligned}
\end{eqnarray}
Plugging into (\ref{equ1}) and (\ref{equ3}), we have
\begin{eqnarray}
\begin{aligned}\label{equ4}
&\E_k\left[f(\X_{k+1})\big| \F_{k-1}\right]-f(\X_k)\\
\leq&-\frac{\eta}{2}\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\widetilde\V_k+\varepsilon}}\right\|_F^2-\frac{\eta}{4}\E_k\left[\left\|\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2\big| \F_{k-1}\right]+\frac{\eta}{2\sqrt{\varepsilon}}\E_k\left[\left\|\nabla f(\X_k)-\M_k\right\|_F^2\big| \F_{k-1}\right]
\end{aligned}
\end{eqnarray}
and
\begin{eqnarray}
\begin{aligned}\label{equ5}
&\E_k\left[f(\X_{k+1})-f^*+\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\nabla f(\X_k)-\M_k\right\|_F^2+\frac{\eta}{4}\left\|\frac{\bP_{k-1}^T\M_k\bQ_{k-1}}{\sqrt[4]{\V_k+\varepsilon}}\right\|_F^2\big| \F_{k-1}\right]\\
\leq&f(\X_k)-f^*-\frac{\eta}{2}\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\widetilde\V_k+\varepsilon}}\right\|_F^2\\
& +\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\M_{k-1}-\nabla f(\X_{k-1})\right\|_F^2+ \frac{\eta}{4}\left\|\frac{\bP_{k-2}^T\M_{k-1}\bQ_{k-2}}{\sqrt[4]{\V_{k-1}+\varepsilon}}\right\|_F^2 + \frac{\eta(1-\theta)\sigma_F^2}{2\sqrt{\varepsilon}}.
\end{aligned}
\end{eqnarray}
Taking expectation with respect to $\F_{k-1}$ and summing (\ref{equ4}) with $k=1$ and (\ref{equ5}) over $k=2,3,\cdots,K$, we have
\begin{eqnarray}
\begin{aligned}\label{equ6}
&\E_{\F_K}\left[f(\X_{K+1})-f^*+\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\nabla f(\X_K)-\M_K\right\|_F^2+\frac{\eta}{4}\left\|\frac{\bP_{K-1}^T\M_K\bQ_{K-1}}{\sqrt[4]{\V_K+\varepsilon}}\right\|_F^2\right]\\
\leq&f(\X_1)-f^*-\frac{\eta}{2}\sum_{k=1}^K\E_{\F_{k-1}}\left[\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\widetilde\V_k+\varepsilon}}\right\|_F^2\right]\\
& +\left(\frac{\eta}{2\sqrt{\varepsilon}}+\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\right)\E_{\F_1}\left[\left\|\M_1-\nabla f(\X_1)\right\|_F^2\right]+ \frac{(K-1)\eta(1-\theta)\sigma_F^2}{2\sqrt{\varepsilon}}\\
=&f(\X_1)\hspace*{-0.05cm}-\hspace*{-0.05cm}f^*\hspace*{-0.05cm}-\hspace*{-0.05cm}\frac{\eta}{2}\hspace*{-0.05cm}\sum_{k=1}^K\hspace*{-0.05cm}\E_{\F_{k-1}}\hspace*{-0.15cm}\left[\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\widetilde\V_k+\varepsilon}}\right\|_F^2\right] \hspace*{-0.1cm}+\hspace*{-0.05cm}\frac{\eta}{2\sqrt{\varepsilon}(1\hspace*{-0.05cm}-\hspace*{-0.05cm}\theta)}\E_{\F_1}\hspace*{-0.15cm}\left[\left\|\M_1\hspace*{-0.1cm}-\hspace*{-0.1cm}\nabla f(\X_1)\right\|_F^2\right]\hspace*{-0.05cm}+\hspace*{-0.05cm} \frac{(\hspace*{-0.05cm}K\hspace*{-0.05cm}-\hspace*{-0.05cm}1)\eta(1\hspace*{-0.05cm}-\hspace*{-0.05cm}\theta)\sigma_F^2}{2\sqrt{\varepsilon}}.\hspace*{-0.65cm}
\end{aligned}
\end{eqnarray}
As the gradient is $L$-Lipschitz, we have
\begin{eqnarray}
\begin{aligned}\notag
&f^*\leq f\left(\X-\frac{1}{L}\nabla f(\X)\right)\leq f(\X)-\frac{1}{L}\<\nabla f(\X),\nabla f(\X)\>+\frac{L}{2}\left\|\frac{1}{L}\nabla f(\X)\right\|_F^2=f(\X)-\frac{1}{2L}\left\|\nabla f(\X)\right\|_F^2.
\end{aligned}
\end{eqnarray}
Using the recursion of $\M_1$ and $\M_0=\0$, we have
\begin{eqnarray}
\begin{aligned}\notag
\E_{\F_1}\left[\left\|\nabla f(\X_1)-\M_1\right\|_F^2\right]=&\E_{\F_1}\left[\left\|\theta\nabla f(\X_1)+(1-\theta)\left(\nabla f(\X_1)-\G_1\right)\right\|_F^2\right]\\
=&\theta^2\left\|\nabla f(\X_1)\right\|_F^2+(1-\theta)^2\E_{\F_1}\left[\left\|\nabla f(\X_1)-\G_1\right\|_F^2\right]\\
\leq& 2L\left(f(\X_1)-f^*\right) + (1-\theta)^2\sigma_F^2.
\end{aligned}
\end{eqnarray}
Plugging into (\ref{equ6}), we have
\begin{eqnarray}
\begin{aligned}\notag
&\E_{\F_K}\left[f(\X_{K+1})-f^*+\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\nabla f(\X_K)-\M_K\right\|_F^2+\frac{\eta}{4}\left\|\frac{\bP_{K-1}^T\M_K\bQ_{K-1}}{\sqrt[4]{\V_K+\varepsilon}}\right\|_F^2\right]\\
\leq&f(\X_1)-f^*-\frac{\eta}{2}\sum_{k=1}^K\E_{\F_{k-1}}\left[\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\widetilde\V_k+\varepsilon}}\right\|_F^2\right] +\frac{L\eta}{\sqrt{\varepsilon}(1-\theta)}\left(f(\X_1)-f^*\right)+ \frac{K\eta(1-\theta)\sigma_F^2}{2\sqrt{\varepsilon}}\\
\leq&f(\X_1)-f^*-\frac{\eta}{2}\sum_{k=1}^K\E_{\F_{k-1}}\left[\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\widetilde\V_k+\varepsilon}}\right\|_F^2\right] +\frac{L\eta}{\sqrt{\varepsilon}(1-\theta)}\left(f(\X_1)-f^*\right)+ \frac{K\eta(1-\theta)\hat\sigma_F^2}{2\sqrt{\varepsilon}},
\end{aligned}
\end{eqnarray}
where we denote $\hat\sigma_F^2=\max\left\{\sigma_F^2,\frac{L\left(f(\X_1)-f^*\right)}{K\gamma^2}\right\}$ with any $\gamma\in(0,1]$. So we have
\begin{eqnarray}
\begin{aligned}\notag
\sum_{k=1}^K\E_{\F_{k-1}}\left[\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\widetilde\V_k+\varepsilon}}\right\|_F^2\right]\leq&\frac{2}{\eta}\left(f(\X_1)-f^*\right) +\frac{2L}{\sqrt{\varepsilon}(1-\theta)}\left(f(\X_1)-f^*\right)+ \frac{K(1-\theta)\hat\sigma_F^2}{\sqrt{\varepsilon}}\\
=&7\sqrt{\frac{K\hat\sigma_F^2L\left(f(\X_1)-f^*\right)}{\varepsilon}}
\end{aligned}
\end{eqnarray}
by letting $1-\theta=\sqrt{\frac{L\left(f(\X_1)-f^*\right)}{K\hat\sigma_F^2}}$ and $\eta=\sqrt{\frac{\varepsilon\left(f(\X_1)-f^*\right)}{4LK\hat\sigma_F^2}}$, which also satisfies $\eta\leq\frac{\sqrt{\varepsilon}}{2L}$ and $\eta^2\leq\frac{\varepsilon(1-\theta)^2}{4L^2}\leq\frac{\varepsilon(1-\theta)^2}{2L^2}$. Using Holder's inequality and Lemma \ref{second-moment-lemma}, we have
\begin{eqnarray}
\begin{aligned}\notag
&\left(\sum_{k=1}^K\E_{\F_{k-1}}\left[\left\|\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}\right\|_1\right]\right)^2=\left(\sum_{k=1}^K\sum_{i=1}^m\sum_{j=1}^n\E_{\F_{k-1}}\left[\left|\bP_{k-1,:,i}^T\nabla f(\X_k)\bQ_{k-1,:,j}\right|\right]\right)^2\\
\leq&\left(\sum_{k=1}^K\sum_{i=1}^m\sum_{j=1}^n\E_{\F_{k-1}}\left[\frac{\left|\bP_{k-1,:,i}^T\nabla f(\X_k)\bQ_{k-1,:,j}\right|^2}{\sqrt{\widetilde\V_{k,i,j}+\varepsilon}}\right]\right)\left(\sum_{k=1}^K\sum_{i=1}^m\sum_{j=1}^n\E_{\F_{k-1}}\left[\sqrt{\widetilde\V_{k,i,j}+\varepsilon}\right]\right)\\
\leq&\left(\sum_{k=1}^K\E_{\F_{k-1}}\left[\left\|\frac{\bP_{k-1}^T\nabla f(\X_t)\bQ_{k-1}}{\sqrt[4]{\widetilde\V_k+\varepsilon}}\right\|_F^2\right]\right)\left(Kmn\sqrt{\sigma_{op}^2+\varepsilon}+2\sum_{k=1}^K\E_{\F_{k-1}}\left[\left\|\frac{\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}}{\sqrt[4]{\widetilde\V_k+\varepsilon}}\right\|_F^2\right]\right)\\
\leq&\left(7\sqrt{\frac{K\hat\sigma_F^2L\left(f(\X_1)-f^*\right)}{\varepsilon}}\right)\left(Kmn\sqrt{\sigma_{op}^2+\varepsilon}+14\sqrt{\frac{K\hat\sigma_F^2L\left(f(\X_1)-f^*\right)}{\varepsilon}}\right)
\end{aligned}
\end{eqnarray}
and
\begin{eqnarray}
\begin{aligned}\notag
\frac{1}{K}\sum_{k=1}^K\E_{\F_{k-1}}\left[\left\|\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}\right\|_1\right]
\leq&10\sqrt{\frac{\hat\sigma_F^2L\left(f(\X_1)-f^*\right)}{K\varepsilon}}+\sqrt{7mn}\sqrt[4]{\left(\sigma_{op}^2+\varepsilon\right)\frac{\hat\sigma_F^2L\left(f(\X_1)-f^*\right)}{K\varepsilon}}\\
=&10\sqrt{\frac{\hat\sigma_F^2L\left(f(\X_1)-f^*\right)}{K\sigma_{op}^2}}+4\sqrt{mn}\sqrt[4]{\frac{\hat\sigma_F^2L\left(f(\X_1)-f^*\right)}{K}}
\end{aligned}
\end{eqnarray}
by letting $\varepsilon=\sigma_{op}^2$. From Lemma \ref{nuclear-l1-norms}, we have
\begin{eqnarray}
\begin{aligned}\notag
\left\|\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}\right\|_1\geq \left\|\bP_{k-1}^T\nabla f(\X_k)\bQ_{k-1}\right\|_*=\left\|\nabla f(\X_k)\right\|_*,
\end{aligned}
\end{eqnarray}
where we use the fact that nuclear norm is the unitarily invariant norm in the last equation.

