=&-\frac{\eta}{2}\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}\right\|_F^2-\frac{\eta}{2}\left\|\frac{\mathbf{P}_{k-1}^T\mathbf{M}_k\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}\right\|_F^2\\
&+\frac{\eta}{2}\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}-\frac{\mathbf{P}_{k-1}^T\mathbf{M}_k\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}\right\|_F^2+\frac{L\eta^2}{2\sqrt{\varepsilon}}\left\|\frac{\mathbf{P}_{k-1}^T\mathbf{M}_k\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}\right\|_F^2\\
\overset{b}\leq&-\frac{\eta}{2}\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}\right\|_F^2-\frac{\eta}{4}\left\|\frac{\mathbf{P}_{k-1}^T\mathbf{M}_k\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}\right\|_F^2+\frac{\eta}{2\sqrt{\varepsilon}}\left\|\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}-\mathbf{P}_{k-1}^T\mathbf{M}_k\mathbf{Q}_{k-1}\right\|_F^2\\
\overset{c}=&-\frac{\eta}{2}\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}\right\|_F^2-\frac{\eta}{4}\left\|\frac{\mathbf{P}_{k-1}^T\mathbf{M}_k\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}\right\|_F^2+\frac{\eta}{2\sqrt{\varepsilon}}\left\|\nabla f(\mathbf{X}_k)-\mathbf{M}_k\right\|_F^2,
\end{aligned}
\end{eqnarray}
where we use the fact that $\|\cdot\|_F$ is a unitarily invariant norm such that $\|\mathbf{P}\mathbf{A}\mathbf{Q}^T\|_F=\|\mathbf{A}\|_F$ for orthogonal matrices $\mathbf{P}$ and $\mathbf{Q}$ in $\overset{a}=$ and $\overset{c}=$, and let $\eta\leq\frac{\sqrt{\varepsilon}}{2L}$ in $\overset{b}\leq$. Taking expectation on both sides of (\ref{equ1}) with respect to $\zeta_k$ conditioned on $\mathcal{F}_{k-1}$, multiplying both sides of (\ref{GM-dif-equ}) by $\frac{\eta}{2\sqrt{\varepsilon}(1-\theta)}$, and adding to (\ref{equ1}), we have
\begin{eqnarray}
\begin{aligned}\label{equ3}
&\mathbb{E}_k\left[f(\mathbf{X}_{k+1})-f^*+\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\nabla f(\mathbf{X}_k)-\mathbf{M}_k\right\|_F^2+\frac{\eta}{4}\left\|\frac{\mathbf{P}_{k-1}^T\mathbf{M}_k\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}\right\|_F^2\big| \mathcal{F}_{k-1}\right]\\
\leq&f(\mathbf{X}_k)-f^*-\frac{\eta}{2}\mathbb{E}_k\left[\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}\right\|_F^2\big| \mathcal{F}_{k-1}\right]\\
& +\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\mathbf{M}_{k-1}-\nabla f(\mathbf{X}_{k-1})\right\|_F^2+ \frac{L^2\eta^3}{2\varepsilon(1-\theta)^2}\left\|\frac{\mathbf{P}_{k-2}^T\mathbf{M}_{k-1}\mathbf{Q}_{k-2}}{\sqrt[4]{\mathbf{V}_{k-1}+\varepsilon}}\right\|_F^2 + \frac{\eta(1-\theta)\sigma_F^2}{2\sqrt{\varepsilon}}\\
\leq&f(\mathbf{X}_k)-f^*-\frac{\eta}{2}\mathbb{E}_k\left[\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}\right\|_F^2\big| \mathcal{F}_{k-1}\right]\\
& +\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\mathbf{M}_{k-1}-\nabla f(\mathbf{X}_{k-1})\right\|_F^2+ \frac{\eta}{4}\left\|\frac{\mathbf{P}_{k-2}^T\mathbf{M}_{k-1}\mathbf{Q}_{k-2}}{\sqrt[4]{\mathbf{V}_{k-1}+\varepsilon}}\right\|_F^2 + \frac{\eta(1-\theta)\sigma_F^2}{2\sqrt{\varepsilon}},
\end{aligned}
\end{eqnarray}
where we let $\eta^2\leq\frac{\varepsilon(1-\theta)^2}{2L^2} $ in the last inequality. Define 
\begin{eqnarray}
\begin{aligned}\label{wide-v-def}
\widetilde \mathbf{V}_k=\beta\mathbf{V}_{k-1}+(1-\beta)\left(\left(\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}\right)^2+\sigma_{op}^2\right).
\end{aligned}
\end{eqnarray}
Since $\mathbf{P}_{k-1}$ and $\mathbf{Q}_{k-1}$ are not random variables given $\mathcal{F}_{k-1}$, we have
\begin{eqnarray}
\begin{aligned}\label{equ2}
&\mathbb{E}_k\left[\left|\mathbf{P}_{k-1,:,i}^T\mathbf{G}_k\mathbf{Q}_{k-1,:,j}\right|^2\big| \mathcal{F}_{k-1}\right]\\
\overset{d}=&\mathbb{E}_k\left[\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2+\left|\mathbf{P}_{k-1,:,i}^T\left(\nabla f(\mathbf{X}_k)-\mathbf{G}_k\right)\mathbf{Q}_{k-1,:,j}\right|^2\Big|\mathcal{F}_{k-1}\right]\\
\overset{e}\leq&\mathbb{E}_k\left[\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2+\left\|\nabla f(\mathbf{X}_k)-\mathbf{G}_k\right\|_{op}^2\Big|\mathcal{F}_{k-1}\right]\\
=&\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2+\mathbb{E}_k\left[\left\|\nabla f(\mathbf{X}_k)-\mathbf{G}_k\right\|_{op}^2\Big|\mathcal{F}_{k-1}\right]\\
\overset{f}\leq&\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2+\sigma_{op}^2, 
\end{aligned}
\end{eqnarray}
where we use Assumption 2 in $\overset{d}=$, $\<\mathbf{x},\mathbf{y}\>\leq\|\mathbf{x}\|\|\mathbf{y}\|$, $\|\mathbf{A}\mathbf{x}\|\leq\|\mathbf{A}\|_{op}\|\mathbf{x}\|$, $\|\mathbf{P}_{k-1,:,i}\|=1$, and $\|\mathbf{Q}_{k-1,:,j}\|=1$ in $\overset{e}\leq$, and Assumption 3 in $\overset{f}\leq$. From the concavity of $\sqrt{x}$ and $-\frac{1}{\sqrt{x}}$, we have
\begin{eqnarray}
\begin{aligned}\notag
\mathbb{E}_k\left[\sqrt{\mathbf{V}_{k,i,j}+\varepsilon}\big| \mathcal{F}_{k-1}\right]\leq& \sqrt{\mathbb{E}_k\left[\mathbf{V}_{k,i,j}\big| \mathcal{F}_{k-1}\right]+\varepsilon}\\
=&\sqrt{\beta\mathbf{V}_{k-1,i,j}+(1-\beta)\mathbb{E}_k\left[\left|\mathbf{P}_{k-1,:,i}^T\mathbf{G}_k\mathbf{Q}_{k-1,:,j}\right|^2\big| \mathcal{F}_{k-1}\right]+\varepsilon}\\
\leq&\sqrt{\beta\mathbf{V}_{k-1,i,j}+(1-\beta)\left(\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2+\sigma_{op}^2\right)+\varepsilon}\\
=&\sqrt{\widetilde \mathbf{V}_{k,i,j}+\varepsilon}
\end{aligned}
\end{eqnarray}
and
\begin{eqnarray}
\begin{aligned}\notag
\mathbb{E}_k\left[-\frac{\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2}{\sqrt{\mathbf{V}_{k,i,j}+\varepsilon}}\big| \mathcal{F}_{k-1}\right]\leq -\frac{\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2}{\sqrt{\mathbb{E}_k\left[\mathbf{V}_{k,i,j}\big| \mathcal{F}_{k-1}\right]+\varepsilon}}= -\frac{\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2}{\sqrt{\widetilde \mathbf{V}_{k,i,j}+\varepsilon}}.
\end{aligned}
\end{eqnarray}
Plugging into (\ref{equ1}) and (\ref{equ3}), we have
\begin{eqnarray}
\begin{aligned}\label{equ4}
&\mathbb{E}_k\left[f(\mathbf{X}_{k+1})\big| \mathcal{F}_{k-1}\right]-f(\mathbf{X}_k)\\
\leq&-\frac{\eta}{2}\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\widetilde\mathbf{V}_k+\varepsilon}}\right\|_F^2-\frac{\eta}{4}\mathbb{E}_k\left[\left\|\frac{\mathbf{P}_{k-1}^T\mathbf{M}_k\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}\right\|_F^2\big| \mathcal{F}_{k-1}\right]+\frac{\eta}{2\sqrt{\varepsilon}}\mathbb{E}_k\left[\left\|\nabla f(\mathbf{X}_k)-\mathbf{M}_k\right\|_F^2\big| \mathcal{F}_{k-1}\right]
\end{aligned}
\end{eqnarray}
and
\begin{eqnarray}
\begin{aligned}\label{equ5}
&\mathbb{E}_k\left[f(\mathbf{X}_{k+1})-f^*+\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\nabla f(\mathbf{X}_k)-\mathbf{M}_k\right\|_F^2+\frac{\eta}{4}\left\|\frac{\mathbf{P}_{k-1}^T\mathbf{M}_k\mathbf{Q}_{k-1}}{\sqrt[4]{\mathbf{V}_k+\varepsilon}}\right\|_F^2\big| \mathcal{F}_{k-1}\right]\\
\leq&f(\mathbf{X}_k)-f^*-\frac{\eta}{2}\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\widetilde\mathbf{V}_k+\varepsilon}}\right\|_F^2\\
& +\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\mathbf{M}_{k-1}-\nabla f(\mathbf{X}_{k-1})\right\|_F^2+ \frac{\eta}{4}\left\|\frac{\mathbf{P}_{k-2}^T\mathbf{M}_{k-1}\mathbf{Q}_{k-2}}{\sqrt[4]{\mathbf{V}_{k-1}+\varepsilon}}\right\|_F^2 + \frac{\eta(1-\theta)\sigma_F^2}{2\sqrt{\varepsilon}}.
\end{aligned}
\end{eqnarray}
Taking expectation with respect to $\mathcal{F}_{k-1}$ and summing (\ref{equ4}) with $k=1$ and (\ref{equ5}) over $k=2,3,\cdots,K$, we have
\begin{eqnarray}
\begin{aligned}\label{equ6}
&\mathbb{E}_{\mathcal{F}_K}\left[f(\mathbf{X}_{K+1})-f^*+\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\nabla f(\mathbf{X}_K)-\mathbf{M}_K\right\|_F^2+\frac{\eta}{4}\left\|\frac{\mathbf{P}_{K-1}^T\mathbf{M}_K\mathbf{Q}_{K-1}}{\sqrt[4]{\mathbf{V}_K+\varepsilon}}\right\|_F^2\right]\\
\leq&f(\mathbf{X}_1)-f^*-\frac{\eta}{2}\sum_{k=1}^K\mathbb{E}_{\mathcal{F}_{k-1}}\left[\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\widetilde\mathbf{V}_k+\varepsilon}}\right\|_F^2\right]\\
& +\left(\frac{\eta}{2\sqrt{\varepsilon}}+\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\right)\mathbb{E}_{\mathcal{F}_1}\left[\left\|\mathbf{M}_1-\nabla f(\mathbf{X}_1)\right\|_F^2\right]+ \frac{(K-1)\eta(1-\theta)\sigma_F^2}{2\sqrt{\varepsilon}}\\
=&f(\mathbf{X}_1)\hspace*{-0.05cm}-\hspace*{-0.05cm}f^*\hspace*{-0.05cm}-\hspace*{-0.05cm}\frac{\eta}{2}\hspace*{-0.05cm}\sum_{k=1}^K\hspace*{-0.05cm}\mathbb{E}_{\mathcal{F}_{k-1}}\hspace*{-0.15cm}\left[\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\widetilde\mathbf{V}_k+\varepsilon}}\right\|_F^2\right] \hspace*{-0.1cm}+\hspace*{-0.05cm}\frac{\eta}{2\sqrt{\varepsilon}(1\hspace*{-0.05cm}-\hspace*{-0.05cm}\theta)}\mathbb{E}_{\mathcal{F}_1}\hspace*{-0.15cm}\left[\left\|\mathbf{M}_1\hspace*{-0.1cm}-\hspace*{-0.1cm}\nabla f(\mathbf{X}_1)\right\|_F^2\right]\hspace*{-0.05cm}+\hspace*{-0.05cm} \frac{(\hspace*{-0.05cm}K\hspace*{-0.05cm}-\hspace*{-0.05cm}1)\eta(1\hspace*{-0.05cm}-\hspace*{-0.05cm}\theta)\sigma_F^2}{2\sqrt{\varepsilon}}.\hspace*{-0.65cm}
\end{aligned}
\end{eqnarray}
As the gradient is $L$-Lipschitz, we have
\begin{eqnarray}
\begin{aligned}\notag
&f^*\leq f\left(\mathbf{X}-\frac{1}{L}\nabla f(\mathbf{X})\right)\leq f(\mathbf{X})-\frac{1}{L}\<\nabla f(\mathbf{X}),\nabla f(\mathbf{X})\>+\frac{L}{2}\left\|\frac{1}{L}\nabla f(\mathbf{X})\right\|_F^2=f(\mathbf{X})-\frac{1}{2L}\left\|\nabla f(\mathbf{X})\right\|_F^2.
\end{aligned}
\end{eqnarray}
Using the recursion of $\mathbf{M}_1$ and $\mathbf{M}_0=\0$, we have
\begin{eqnarray}
\begin{aligned}\notag
\mathbb{E}_{\mathcal{F}_1}\left[\left\|\nabla f(\mathbf{X}_1)-\mathbf{M}_1\right\|_F^2\right]=&\mathbb{E}_{\mathcal{F}_1}\left[\left\|\theta\nabla f(\mathbf{X}_1)+(1-\theta)\left(\nabla f(\mathbf{X}_1)-\mathbf{G}_1\right)\right\|_F^2\right]\\
=&\theta^2\left\|\nabla f(\mathbf{X}_1)\right\|_F^2+(1-\theta)^2\mathbb{E}_{\mathcal{F}_1}\left[\left\|\nabla f(\mathbf{X}_1)-\mathbf{G}_1\right\|_F^2\right]\\
\leq& 2L\left(f(\mathbf{X}_1)-f^*\right) + (1-\theta)^2\sigma_F^2.
\end{aligned}
\end{eqnarray}
Plugging into (\ref{equ6}), we have
\begin{eqnarray}
\begin{aligned}\notag
&\mathbb{E}_{\mathcal{F}_K}\left[f(\mathbf{X}_{K+1})-f^*+\frac{\eta\theta}{2\sqrt{\varepsilon}(1-\theta)}\left\|\nabla f(\mathbf{X}_K)-\mathbf{M}_K\right\|_F^2+\frac{\eta}{4}\left\|\frac{\mathbf{P}_{K-1}^T\mathbf{M}_K\mathbf{Q}_{K-1}}{\sqrt[4]{\mathbf{V}_K+\varepsilon}}\right\|_F^2\right]\\
\leq&f(\mathbf{X}_1)-f^*-\frac{\eta}{2}\sum_{k=1}^K\mathbb{E}_{\mathcal{F}_{k-1}}\left[\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\widetilde\mathbf{V}_k+\varepsilon}}\right\|_F^2\right] +\frac{L\eta}{\sqrt{\varepsilon}(1-\theta)}\left(f(\mathbf{X}_1)-f^*\right)+ \frac{K\eta(1-\theta)\sigma_F^2}{2\sqrt{\varepsilon}}\\
\leq&f(\mathbf{X}_1)-f^*-\frac{\eta}{2}\sum_{k=1}^K\mathbb{E}_{\mathcal{F}_{k-1}}\left[\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\widetilde\mathbf{V}_k+\varepsilon}}\right\|_F^2\right] +\frac{L\eta}{\sqrt{\varepsilon}(1-\theta)}\left(f(\mathbf{X}_1)-f^*\right)+ \frac{K\eta(1-\theta)\hat\sigma_F^2}{2\sqrt{\varepsilon}},
\end{aligned}
\end{eqnarray}
where we denote $\hat\sigma_F^2=\max\left\{\sigma_F^2,\frac{L\left(f(\mathbf{X}_1)-f^*\right)}{K\gamma^2}\right\}$ with any $\gamma\in(0,1]$. So we have
\begin{eqnarray}
\begin{aligned}\notag
\sum_{k=1}^K\mathbb{E}_{\mathcal{F}_{k-1}}\left[\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\widetilde\mathbf{V}_k+\varepsilon}}\right\|_F^2\right]\leq&\frac{2}{\eta}\left(f(\mathbf{X}_1)-f^*\right) +\frac{2L}{\sqrt{\varepsilon}(1-\theta)}\left(f(\mathbf{X}_1)-f^*\right)+ \frac{K(1-\theta)\hat\sigma_F^2}{\sqrt{\varepsilon}}\\
=&7\sqrt{\frac{K\hat\sigma_F^2L\left(f(\mathbf{X}_1)-f^*\right)}{\varepsilon}}
\end{aligned}
\end{eqnarray}
by letting $1-\theta=\sqrt{\frac{L\left(f(\mathbf{X}_1)-f^*\right)}{K\hat\sigma_F^2}}$ and $\eta=\sqrt{\frac{\varepsilon\left(f(\mathbf{X}_1)-f^*\right)}{4LK\hat\sigma_F^2}}$, which also satisfies $\eta\leq\frac{\sqrt{\varepsilon}}{2L}$ and $\eta^2\leq\frac{\varepsilon(1-\theta)^2}{4L^2}\leq\frac{\varepsilon(1-\theta)^2}{2L^2}$. Using Holder's inequality and Lemma \ref{second-moment-lemma}, we have
\begin{eqnarray}
\begin{aligned}\notag
&\left(\sum_{k=1}^K\mathbb{E}_{\mathcal{F}_{k-1}}\left[\left\|\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}\right\|_1\right]\right)^2=\left(\sum_{k=1}^K\sum_{i=1}^m\sum_{j=1}^n\mathbb{E}_{\mathcal{F}_{k-1}}\left[\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|\right]\right)^2\\
\leq&\left(\sum_{k=1}^K\sum_{i=1}^m\sum_{j=1}^n\mathbb{E}_{\mathcal{F}_{k-1}}\left[\frac{\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2}{\sqrt{\widetilde\mathbf{V}_{k,i,j}+\varepsilon}}\right]\right)\left(\sum_{k=1}^K\sum_{i=1}^m\sum_{j=1}^n\mathbb{E}_{\mathcal{F}_{k-1}}\left[\sqrt{\widetilde\mathbf{V}_{k,i,j}+\varepsilon}\right]\right)\\
\leq&\left(\sum_{k=1}^K\mathbb{E}_{\mathcal{F}_{k-1}}\left[\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_t)\mathbf{Q}_{k-1}}{\sqrt[4]{\widetilde\mathbf{V}_k+\varepsilon}}\right\|_F^2\right]\right)\left(Kmn\sqrt{\sigma_{op}^2+\varepsilon}+2\sum_{k=1}^K\mathbb{E}_{\mathcal{F}_{k-1}}\left[\left\|\frac{\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}}{\sqrt[4]{\widetilde\mathbf{V}_k+\varepsilon}}\right\|_F^2\right]\right)\\
\leq&\left(7\sqrt{\frac{K\hat\sigma_F^2L\left(f(\mathbf{X}_1)-f^*\right)}{\varepsilon}}\right)\left(Kmn\sqrt{\sigma_{op}^2+\varepsilon}+14\sqrt{\frac{K\hat\sigma_F^2L\left(f(\mathbf{X}_1)-f^*\right)}{\varepsilon}}\right)
\end{aligned}
\end{eqnarray}
and
\begin{eqnarray}
\begin{aligned}\notag
\frac{1}{K}\sum_{k=1}^K\mathbb{E}_{\mathcal{F}_{k-1}}\left[\left\|\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}\right\|_1\right]
\leq&10\sqrt{\frac{\hat\sigma_F^2L\left(f(\mathbf{X}_1)-f^*\right)}{K\varepsilon}}+\sqrt{7mn}\sqrt[4]{\left(\sigma_{op}^2+\varepsilon\right)\frac{\hat\sigma_F^2L\left(f(\mathbf{X}_1)-f^*\right)}{K\varepsilon}}\\
=&10\sqrt{\frac{\hat\sigma_F^2L\left(f(\mathbf{X}_1)-f^*\right)}{K\sigma_{op}^2}}+4\sqrt{mn}\sqrt[4]{\frac{\hat\sigma_F^2L\left(f(\mathbf{X}_1)-f^*\right)}{K}}
\end{aligned}
\end{eqnarray}
by letting $\varepsilon=\sigma_{op}^2$. From Lemma \ref{nuclear-l1-norms}, we have
\begin{eqnarray}
\begin{aligned}\notag
\left\|\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}\right\|_1\geq \left\|\mathbf{P}_{k-1}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1}\right\|_*=\left\|\nabla f(\mathbf{X}_k)\right\|_*,
\end{aligned}
\end{eqnarray}
where we use the fact that nuclear norm is the unitarily invariant norm in the last equation.

