\label{momentum-bound-lemma}
Suppose that Assumptions 1-3 hold. Then for Algorithm \ref{gsoap}, we have
\begin{eqnarray}
\begin{aligned}\label{GM-dif-equ}
&\mathbb{E}_k\left[\left\|\nabla f(\mathbf{X}_k)-\mathbf{M}_k\right\|_F^2\big|\mathcal{F}_{k-1}\right]\\
\leq&\theta\left\|\mathbf{M}_{k-1}-\nabla f(\mathbf{X}_{k-1})\right\|_F^2 + \frac{L^2\eta^2}{(1-\theta)\sqrt{\varepsilon}}\left\|\frac{\mathbf{P}_{k-2}^T\mathbf{M}_{k-1}\mathbf{Q}_{k-2}}{\sqrt[4]{\mathbf{V}_{k-1}+\varepsilon}}\right\|_F^2 + (1-\theta)^2\sigma_F^2.
\end{aligned}
\end{eqnarray}

\label{second-moment-lemma}
Suppose that Assumptions 2-3 hold. Let $0\leq\beta< 1$ and $\mathbf{V}_0=0$. Then we have
\begin{eqnarray}
\begin{aligned}\notag
\sum_{k=1}^K\sum_{i=1}^m\sum_{j=1}^n \mathbb{E}_{\mathcal{F}_{k-1}}\left[\sqrt{\widetilde\mathbf{V}_{k,i,j}+\varepsilon}\right]\leq Kmn\sqrt{\sigma_{op}^2+\varepsilon}+2\sum_{t=1}^K\mathbb{E}_{\mathcal{F}_{t-1}}\left[\left\|\frac{\mathbf{P}_{t-1}^T\nabla f(\mathbf{X}_t)\mathbf{Q}_{t-1}}{\sqrt[4]{\widetilde\mathbf{V}_t+\varepsilon}}\right\|_F^2\right].
\end{aligned}
\end{eqnarray}

From the definition of $\widetilde\mathbf{V}_k$ in (\ref{wide-v-def}), we have
\begin{eqnarray}
\hspace*{-2cm}\begin{aligned}\notag
&\mathbb{E}_{\mathcal{F}_{k-1}}\left[\sqrt{\widetilde\mathbf{V}_{k,i,j}+\varepsilon}\right]\\
=&\mathbb{E}_{\mathcal{F}_{k-1}}\left[\sqrt{\beta\mathbf{V}_{k-1,i,j}+(1-\beta)\left(\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2+\sigma_{op}^2\right)+\varepsilon}\right]
\end{aligned}
\end{eqnarray}
\begin{eqnarray}
\begin{aligned}\notag
=&\mathbb{E}_{\mathcal{F}_{k-1}}\left[\frac{\beta\mathbf{V}_{k-1,i,j}+(1-\beta)\sigma_{op}^2+\varepsilon}{\sqrt{\beta\mathbf{V}_{k-1,i,j}+(1-\beta)\left(\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2+\sigma_{op}^2\right)+\varepsilon}}\right]\\
& + \mathbb{E}_{\mathcal{F}_{k-1}}\left[\frac{(1-\beta)\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2}{\sqrt{\beta\mathbf{V}_{k-1,i,j}+(1-\beta)\left(\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2+\sigma_{op}^2\right)+\varepsilon}}\right]\\
\leq&\mathbb{E}_{\mathcal{F}_{k-1}}\left[\sqrt{\beta\mathbf{V}_{k-1,i,j}+(1-\beta)\sigma_{op}^2+\varepsilon}\right]+(1-\beta)\mathbb{E}_{\mathcal{F}_{k-1}}\left[\frac{\left|\mathbf{P}_{k-1,:,i}^T\nabla f(\mathbf{X}_k)\mathbf{Q}_{k-1,:,j}\right|^2}{\sqrt{\widetilde\mathbf{V}_{k,i,j}+\varepsilon}}\right].
\end{aligned}
\end{eqnarray}
Consider the first part in the general case. From the recursion of $\mathbf{V}_{k-t,i,j}$, we have
\begin{eqnarray}
\begin{aligned}\notag
&\mathbb{E}_{\mathcal{F}_{k-t}}\left[\sqrt{\beta^t\mathbf{V}_{k-t,i,j}+(1-\beta^t)\sigma_{op}^2+\varepsilon}\right]\\
=&\mathbb{E}_{\mathcal{F}_{k-t}}\left[\sqrt{\beta^{t+1}\mathbf{V}_{k-t-1,i,j}+\beta^t(1-\beta)\left|\mathbf{P}_{k-t-1,:,i}^T\mathbf{G}_{k-t}\mathbf{Q}_{k-t-1,:,j}\right|^2+(1-\beta^t)\sigma_{op}^2+\varepsilon}\right]\\
=&\mathbb{E}_{\mathcal{F}_{k-t-1}}\left[\mathbb{E}_{k-t}\left[\sqrt{\beta^{t+1}\mathbf{V}_{k-t-1,i,j}+\beta^t(1-\beta)\left|\mathbf{P}_{k-t-1,:,i}^T\mathbf{G}_{k-t}\mathbf{Q}_{k-t-1,:,j}\right|^2+(1-\beta^t)\sigma_{op}^2+\varepsilon}\Big|\mathcal{F}_{k-t-1}\right]\right]\\
\overset{a}\leq&\mathbb{E}_{\mathcal{F}_{k-t-1}}\left[\sqrt{\beta^{t+1}\mathbf{V}_{k-t-1,i,j}+\beta^t(1-\beta)\mathbb{E}_{k-t}\left[\left|\mathbf{P}_{k-t-1,:,i}^T\mathbf{G}_{k-t}\mathbf{Q}_{k-t-1,:,j}\right|^2\Big|\mathcal{F}_{k-t-1}\right]+(1-\beta^t)\sigma_{op}^2+\varepsilon}\right]\\
\overset{b}\leq&\mathbb{E}_{\mathcal{F}_{k-t-1}}\left[\sqrt{\beta^{t+1}\mathbf{V}_{k-t-1,i,j}+\beta^t(1-\beta)\left(\left|\mathbf{P}_{k-t-1,:,i}^T\nabla f(\mathbf{X}_{k-t})\mathbf{Q}_{k-t-1,:,j}\right|^2+\sigma_{op}^2\right)+(1-\beta^t)\sigma_{op}^2+\varepsilon}\right]\\
=&\mathbb{E}_{\mathcal{F}_{k-t-1}}\left[\sqrt{\beta^{t+1}\mathbf{V}_{k-t-1,i,j}+\beta^t(1-\beta)\left|\mathbf{P}_{k-t-1,:,i}^T\nabla f(\mathbf{X}_{k-t})\mathbf{Q}_{k-t-1,:,j}\right|^2+(1-\beta^{t+1})\sigma_{op}^2+\varepsilon}\right]\\
=&\mathbb{E}_{\mathcal{F}_{k-t-1}}\left[\frac{\beta^{t+1}\mathbf{V}_{k-t-1,i,j}+(1-\beta^{t+1})\sigma_{op}^2+\varepsilon}{\sqrt{\beta^{t+1}\mathbf{V}_{k-t-1,i,j}+\beta^t(1-\beta)\left|\mathbf{P}_{k-t-1,:,i}^T\nabla f(\mathbf{X}_{k-t})\mathbf{Q}_{k-t-1,:,j}\right|^2+(1-\beta^{t+1})\sigma_{op}^2+\varepsilon}}\right]\\
& + \mathbb{E}_{\mathcal{F}_{k-t-1}}\left[\frac{\beta^t(1-\beta)\left|\mathbf{P}_{k-t-1,:,i}^T\nabla f(\mathbf{X}_{k-t})\mathbf{Q}_{k-t-1,:,j}\right|^2}{\sqrt{\beta^{t+1}\mathbf{V}_{k-t-1,i,j}+\beta^t(1-\beta)\left|\mathbf{P}_{k-t-1,:,i}^T\nabla f(\mathbf{X}_{k-t})\mathbf{Q}_{k-t-1,:,j}\right|^2+(1-\beta^{t+1})\sigma_{op}^2+\varepsilon}}\right]\\
\leq&\mathbb{E}_{\mathcal{F}_{k-t-1}}\left[\sqrt{\beta^{t+1}\mathbf{V}_{k-t-1,i,j}+(1-\beta^{t+1})\sigma_{op}^2+\varepsilon}\right]\\
& + \mathbb{E}_{\mathcal{F}_{k-t-1}}\left[\frac{\beta^t(1-\beta)\left|\mathbf{P}_{k-t-1,:,i}^T\nabla f(\mathbf{X}_{k-t})\mathbf{Q}_{k-t-1,:,j}\right|^2}{\sqrt{\beta^{t+1}\mathbf{V}_{k-t-1,i,j}+\beta^t(1-\beta)\left|\mathbf{P}_{k-t-1,:,i}^T\nabla f(\mathbf{X}_{k-t})\mathbf{Q}_{k-t-1,:,j}\right|^2+(\beta^t-\beta^{t+1})\sigma_{op}^2+\beta^t\varepsilon}}\right]\\
=&\mathbb{E}_{\mathcal{F}_{k-t-1}}\hspace*{-0.1cm}\left[\sqrt{\beta^{t+1}\mathbf{V}_{k-t-1,i,j}+(1-\beta^{t+1})\sigma_{op}^2+\varepsilon}\right]+\sqrt{\beta^t}(1-\beta)\mathbb{E}_{\mathcal{F}_{k-t-1}}\hspace*{-0.1cm}\left[\frac{\left|\mathbf{P}_{k-t-1,:,i}^T\nabla f(\mathbf{X}_{k-t})\mathbf{Q}_{k-t-1,:,j}\right|^2}{\sqrt{\widetilde\mathbf{V}_{k-t,i,j}+\varepsilon}}\right]\hspace*{-0.1cm},
\end{aligned}
\end{eqnarray}
where we use the concavity of $\sqrt{x}$ in $\overset{a}\leq$ and a similar induction to (\ref{equ2}) in $\overset{b}\leq$. Applying the above inequality recursively for $t=1,2,\cdots,k-1$, we have
\begin{eqnarray}
\begin{aligned}\notag
&\mathbb{E}_{\mathcal{F}_{k-1}}\left[\sqrt{\beta\mathbf{V}_{k-1,i,j}+(1-\beta)\sigma_{op}^2+\varepsilon}\right]\\
\leq&\sqrt{\beta^k\mathbf{V}_{0,i,j}+(1-\beta^k)\sigma_{op}^2+\varepsilon}+\sum_{t=1}^{k-1}\sqrt{\beta^t}(1-\beta)\mathbb{E}_{\mathcal{F}_{k-t-1}}\left[\frac{\left|\mathbf{P}_{k-t-1,:,i}^T\nabla f(\mathbf{X}_{k-t})\mathbf{Q}_{k-t-1,:,j}\right|^2}{\sqrt{\widetilde\mathbf{V}_{k-t,i,j}+\varepsilon}}\right]\\
=&\sqrt{\beta^k\mathbf{V}_{0,i,j}+(1-\beta^k)\sigma_{op}^2+\varepsilon}+\sum_{t=1}^{k-1}\sqrt{\beta^{k-t}}(1-\beta)\mathbb{E}_{\mathcal{F}_{t-1}}\left[\frac{\left|\mathbf{P}_{t-1,:,i}^T\nabla f(\mathbf{X}_t)\mathbf{Q}_{t-1,:,j}\right|^2}{\sqrt{\widetilde\mathbf{V}_{t,i,j}+\varepsilon}}\right]
\end{aligned}
\end{eqnarray}
and
\begin{eqnarray}
\begin{aligned}\notag
\mathbb{E}_{\mathcal{F}_{k-1}}\left[\sqrt{\widetilde\mathbf{V}_{k,i,j}+\varepsilon}\right]\leq& \sqrt{\beta^k\mathbf{V}_{0,i,j}+(1-\beta^k)\sigma_{op}^2+\varepsilon}+\sum_{t=1}^k\sqrt{\beta^{k-t}}(1-\beta)\mathbb{E}_{\mathcal{F}_{t-1}}\left[\frac{\left|\mathbf{P}_{t-1,:,i}^T\nabla f(\mathbf{X}_t)\mathbf{Q}_{t-1,:,j}\right|^2}{\sqrt{\widetilde\mathbf{V}_{t,i,j}+\varepsilon}}\right]\\
\leq&\sqrt{\sigma_{op}^2+\varepsilon}+\sum_{t=1}^k\sqrt{\beta^{k-t}}(1-\beta)\mathbb{E}_{\mathcal{F}_{t-1}}\left[\frac{\left|\mathbf{P}_{t-1,:,i}^T\nabla f(\mathbf{X}_t)\mathbf{Q}_{t-1,:,j}\right|^2}{\sqrt{\widetilde\mathbf{V}_{t,i,j}+\varepsilon}}\right],
\end{aligned}
\end{eqnarray}
where we use $\mathbf{V}_0=\0$. Summing over $i=1,2,\cdots,m$, $j=1,2,\cdots,n$, and $k=1,2,\cdots,K$, we have
\begin{eqnarray}
\begin{aligned}\notag
&\sum_{k=1}^K\sum_{i=1}^m\sum_{j=1}^n \mathbb{E}_{\mathcal{F}_{k-1}}\left[\sqrt{\widetilde\mathbf{V}_{k,i,j}+\varepsilon}\right]\\
\leq& Kmn\sqrt{\sigma_{op}^2+\varepsilon}+\sum_{k=1}^K\sum_{t=1}^k\sqrt{\beta^{k-t}}(1-\beta)\sum_{i=1}^m\sum_{j=1}^n\mathbb{E}_{\mathcal{F}_{t-1}}\left[\frac{\left|\mathbf{P}_{t-1,:,i}^T\nabla f(\mathbf{X}_t)\mathbf{Q}_{t-1,:,j}\right|^2}{\sqrt{\widetilde\mathbf{V}_{t,i,j}+\varepsilon}}\right]\\
=& Kmn\sqrt{\sigma_{op}^2+\varepsilon}+\sum_{t=1}^K\sum_{k=t}^K\sqrt{\beta^{k-t}}(1-\beta)\sum_{i=1}^m\sum_{j=1}^n\mathbb{E}_{\mathcal{F}_{t-1}}\left[\frac{\left|\mathbf{P}_{t-1,:,i}^T\nabla f(\mathbf{X}_t)\mathbf{Q}_{t-1,:,j}\right|^2}{\sqrt{\widetilde\mathbf{V}_{t,i,j}+\varepsilon}}\right]\\
\leq& Kmn\sqrt{\sigma_{op}^2+\varepsilon}+\frac{1-\beta}{1-\sqrt{\beta}}\sum_{t=1}^K\sum_{i=1}^m\sum_{j=1}^n\mathbb{E}_{\mathcal{F}_{t-1}}\left[\frac{\left|\mathbf{P}_{t-1,:,i}^T\nabla f(\mathbf{X}_t)\mathbf{Q}_{t-1,:,j}\right|^2}{\sqrt{\widetilde\mathbf{V}_{t,i,j}+\varepsilon}}\right]\\
=& Kmn\sqrt{\sigma_{op}^2+\varepsilon}+(1+\sqrt{\beta})\sum_{t=1}^K\sum_{i=1}^m\sum_{j=1}^n\mathbb{E}_{\mathcal{F}_{t-1}}\left[\frac{\left|\mathbf{P}_{t-1,:,i}^T\nabla f(\mathbf{X}_t)\mathbf{Q}_{t-1,:,j}\right|^2}{\sqrt{\widetilde\mathbf{V}_{t,i,j}+\varepsilon}}\right]\\
=& Kmn\sqrt{\sigma_{op}^2+\varepsilon}+(1+\sqrt{\beta})\sum_{t=1}^K\mathbb{E}_{\mathcal{F}_{t-1}}\left[\left\|\frac{\mathbf{P}_{t-1}^T\nabla f(\mathbf{X}_t)\mathbf{Q}_{t-1}}{\sqrt[4]{\widetilde\mathbf{V}_t+\varepsilon}}\right\|_F^2\right].
\end{aligned}
\end{eqnarray}

